	u32 page_order;
	u32 page_offset;
	dma_addr_t dma_addr;
	u32 len;
};

struct mqnic_ring {
	// written on enqueue (i.e. start_xmit)
	u32 prod_ptr;
	u64 bytes;
	u64 packets;
	u64 dropped_packets;
	struct netdev_queue *tx_queue;

	// written from completion
	u32 cons_ptr ____cacheline_aligned_in_smp;
	u64 ts_s;
	u8 ts_valid;

	// mostly constant
	u32 size;
	u32 full_size;
	u32 size_mask;
	u32 stride;

	u32 mtu;
	u32 page_order;

	u32 desc_block_size;
	u32 log_desc_block_size;

	size_t buf_size;
	u8 *buf;
	dma_addr_t buf_dma_addr;

	union {
		struct mqnic_tx_info *tx_info;
		struct mqnic_rx_info *rx_info;
	};

	struct device *dev;
	struct mqnic_if *interface;
	struct mqnic_priv *priv;
	int index;
	struct mqnic_cq *cq;
	int enabled;

	u8 __iomem *hw_addr;
} ____cacheline_aligned_in_smp;

struct mqnic_cq {
	u32 cons_ptr;

	u32 size;
	u32 size_mask;
	u32 stride;

	size_t buf_size;
	u8 *buf;
	dma_addr_t buf_dma_addr;

	struct device *dev;
	struct mqnic_if *interface;
	struct napi_struct napi;
	int cqn;
	struct mqnic_eq *eq;
	struct mqnic_ring *src_ring;
	int enabled;

	void (*handler)(struct mqnic_cq *cq);

	u8 __iomem *hw_addr;
};

struct mqnic_eq {
	u32 cons_ptr;

	u32 size;
	u32 size_mask;
	u32 stride;

	size_t buf_size;
	u8 *buf;
	dma_addr_t buf_dma_addr;

	struct device *dev;
	struct mqnic_if *interface;
	int eqn;
	struct mqnic_irq *irq;
	int enabled;

	struct notifier_block irq_nb;

	void (*handler)(struct mqnic_eq *eq);

	spinlock_t table_lock;
	struct radix_tree_root cq_table;

	u8 __iomem *hw_addr;
};

struct mqnic_sched {
	struct device *dev;
	struct mqnic_if *interface;
	struct mqnic_sched_block *sched_block;

	struct mqnic_reg_block *rb;

	int index;

	u32 type;
	u32 offset;
	u32 queue_count;
	u32 queue_stride;

	int tc_count;
	int port_count;
	int channel_count;
	int fc_scale;

	int enable_count;

	struct list_head sched_port_list;

	u8 __iomem *hw_addr;
};

struct mqnic_sched_port {
	struct mqnic_sched *sched;
	int index;
	struct list_head list;
	struct list_head free_list;
};

struct mqnic_port {
	struct device *dev;
	struct mqnic_if *interface;

	struct mqnic_reg_block *port_rb;
	struct mqnic_reg_block *rb_list;
	struct mqnic_reg_block *port_ctrl_rb;

	int index;
	int phys_index;

	u32 port_features;

	struct devlink_port dl_port;
};

struct mqnic_sched_block {
	struct device *dev;
	struct mqnic_if *interface;

	struct mqnic_reg_block *block_rb;
	struct mqnic_reg_block *rb_list;

	int index;

	u32 sched_count;
	struct mqnic_sched *sched[MQNIC_MAX_PORTS];
};

struct mqnic_if {
	struct device *dev;
	struct mqnic_dev *mdev;

	struct mqnic_reg_block *rb_list;
	struct mqnic_reg_block *if_ctrl_rb;
	struct mqnic_reg_block *eq_rb;
	struct mqnic_reg_block *cq_rb;
	struct mqnic_reg_block *txq_rb;
	struct mqnic_reg_block *rxq_rb;
	struct mqnic_reg_block *rx_queue_map_rb;

	int index;

	u32 if_features;

	u32 max_tx_mtu;
	u32 max_rx_mtu;
	u32 tx_fifo_depth;
	u32 rx_fifo_depth;

	struct mqnic_res *eq_res;
	struct mqnic_res *cq_res;
	struct mqnic_res *txq_res;
	struct mqnic_res *rxq_res;

	u32 eq_count;
	struct rw_semaphore eq_table_sem;
	struct radix_tree_root eq_table;

	u32 port_count;
	struct mqnic_port *port[MQNIC_MAX_PORTS];

	u32 sched_block_count;
	struct mqnic_sched_block *sched_block[MQNIC_MAX_PORTS];

	spinlock_t free_sched_port_list_lock;
	struct list_head free_sched_port_list;

	u32 max_desc_block_size;

	u32 rx_queue_map_indir_table_size;
	u8 __iomem *rx_queue_map_indir_table[MQNIC_MAX_PORTS];

	resource_size_t hw_regs_size;
	u8 __iomem *hw_addr;
	u8 __iomem *csr_hw_addr;

	u32 ndev_count;
	struct list_head ndev_list;

	struct i2c_client *mod_i2c_client;
};

struct mqnic_priv {
	struct device *dev;
	struct net_device *ndev;
	struct devlink_port *dl_port;
	struct mqnic_dev *mdev;
	struct mqnic_if *interface;

	spinlock_t stats_lock;

	bool registered;
	bool port_up;

	u32 if_features;

	unsigned int link_status;
	struct timer_list link_status_timer;

	u32 txq_count;
	u32 rxq_count;

	u32 tx_ring_size;
	u32 rx_ring_size;

	struct rw_semaphore txq_table_sem;
	struct radix_tree_root txq_table;

	struct rw_semaphore rxq_table_sem;
	struct radix_tree_root rxq_table;

	struct mqnic_sched_port *sched_port;
	struct mqnic_port *port;

	u32 max_desc_block_size;

	u32 rx_queue_map_indir_table_size;
	u32 *rx_queue_map_indir_table;

	struct hwtstamp_config hwts_config;

	struct list_head ndev_list;

	struct i2c_client *mod_i2c_client;
};

